import{_ as o,c as a,o as i,ag as e}from"./chunks/framework.DK1-H3E1.js";const p=JSON.parse('{"title":"工具使用（Tool Use）：让模型从“会说”到“会做”","description":"","frontmatter":{"order":18},"headers":[],"relativePath":"ai/tool-use.md","filePath":"ai/tool-use.md","lastUpdated":1772197851000}'),t={name:"ai/tool-use.md"};function r(s,l,n,h,u,d){return i(),a("div",null,l[0]||(l[0]=[e('<h1 id="工具使用-tool-use-让模型从-会说-到-会做" tabindex="-1">工具使用（Tool Use）：让模型从“会说”到“会做” <a class="header-anchor" href="#工具使用-tool-use-让模型从-会说-到-会做" aria-label="Permalink to &quot;工具使用（Tool Use）：让模型从“会说”到“会做”&quot;">​</a></h1><blockquote><p>📅 主题：LLM 如何调用外部工具，完成可执行任务</p></blockquote><h2 id="一、什么是-tool-use" tabindex="-1">一、什么是 Tool Use <a class="header-anchor" href="#一、什么是-tool-use" aria-label="Permalink to &quot;一、什么是 Tool Use&quot;">​</a></h2><p><strong>Tool Use（工具使用）</strong> 指的是：<br> 模型在推理过程中，不只生成文本，还能按需调用外部能力（API、数据库、检索、代码执行、文件系统等），再基于工具返回结果继续推理并输出答案。</p><p>简单理解：</p><ul><li>纯 LLM：只靠参数记忆回答</li><li>Tool Use：需要什么能力就去调用什么工具</li></ul><p>这让模型从“语言生成器”变成“任务执行者”。</p><hr><h2 id="二、为什么-tool-use-很重要" tabindex="-1">二、为什么 Tool Use 很重要 <a class="header-anchor" href="#二、为什么-tool-use-很重要" aria-label="Permalink to &quot;二、为什么 Tool Use 很重要&quot;">​</a></h2><p>在真实业务里，很多问题不可能仅靠模型参数解决：</p><ol><li><strong>需要最新数据</strong>：例如实时价格、天气、库存</li><li><strong>需要精确计算</strong>：复杂计算、代码执行、SQL 聚合</li><li><strong>需要系统操作</strong>：发消息、写工单、更新数据库</li><li><strong>需要私有知识</strong>：企业文档、内部系统、权限数据</li></ol><p>Tool Use 的价值：</p><ul><li>提升准确性（有外部证据）</li><li>降低幻觉（不是“猜”，而是“查”）</li><li>扩展能力边界（可执行真实动作）</li></ul><hr><h2 id="三、tool-use-的基本流程" tabindex="-1">三、Tool Use 的基本流程 <a class="header-anchor" href="#三、tool-use-的基本流程" aria-label="Permalink to &quot;三、Tool Use 的基本流程&quot;">​</a></h2><p>典型流程如下：</p><ol><li>用户提出任务</li><li>模型判断是否需要调用工具</li><li>选择工具并生成参数</li><li>系统执行工具调用</li><li>将结果回传给模型</li><li>模型基于结果继续推理并输出</li></ol><p>可以写成：</p><p><code>问题 -&gt; 选择工具 -&gt; 执行 -&gt; 观察结果 -&gt; 生成最终答案</code></p><p>这也是 ReAct / Agent 工作流中的核心闭环。</p><hr><h2 id="四、工具接口设计-决定可用性" tabindex="-1">四、工具接口设计：决定可用性 <a class="header-anchor" href="#四、工具接口设计-决定可用性" aria-label="Permalink to &quot;四、工具接口设计：决定可用性&quot;">​</a></h2><p>工具是否好用，关键看接口定义质量。建议：</p><h3 id="_4-1-明确工具职责" tabindex="-1">4.1 明确工具职责 <a class="header-anchor" href="#_4-1-明确工具职责" aria-label="Permalink to &quot;4.1 明确工具职责&quot;">​</a></h3><ul><li>一个工具只做一件事（高内聚）</li><li>命名清晰（<code>searchDocs</code>、<code>runSql</code>、<code>sendMessage</code>）</li></ul><h3 id="_4-2-参数结构化" tabindex="-1">4.2 参数结构化 <a class="header-anchor" href="#_4-2-参数结构化" aria-label="Permalink to &quot;4.2 参数结构化&quot;">​</a></h3><ul><li>使用明确 schema（字段类型、必填项、枚举值）</li><li>给出示例参数，减少模型调用错误</li></ul><h3 id="_4-3-返回可解析" tabindex="-1">4.3 返回可解析 <a class="header-anchor" href="#_4-3-返回可解析" aria-label="Permalink to &quot;4.3 返回可解析&quot;">​</a></h3><ul><li>返回结构化结果（JSON）</li><li>包含状态码、错误信息、关键结果字段</li></ul><h3 id="_4-4-错误可恢复" tabindex="-1">4.4 错误可恢复 <a class="header-anchor" href="#_4-4-错误可恢复" aria-label="Permalink to &quot;4.4 错误可恢复&quot;">​</a></h3><ul><li>可预期错误（超时、权限不足、参数不合法）要有标准化返回</li><li>方便模型或编排层决定重试/降级</li></ul><hr><h2 id="五、常见工具类型" tabindex="-1">五、常见工具类型 <a class="header-anchor" href="#五、常见工具类型" aria-label="Permalink to &quot;五、常见工具类型&quot;">​</a></h2><ol><li><strong>检索类</strong>：搜索文档、知识库、网页</li><li><strong>数据类</strong>：数据库查询、指标系统</li><li><strong>执行类</strong>：代码运行、脚本调用、命令执行</li><li><strong>业务类</strong>：工单系统、IM 发送、CRM 操作</li><li><strong>内容类</strong>：读写文件、生成报告、文档处理</li></ol><p>在生产系统中，工具通常会按权限域分组，避免模型访问不必要的高风险能力。</p><hr><h2 id="六、tool-use-的关键工程问题" tabindex="-1">六、Tool Use 的关键工程问题 <a class="header-anchor" href="#六、tool-use-的关键工程问题" aria-label="Permalink to &quot;六、Tool Use 的关键工程问题&quot;">​</a></h2><h2 id="_6-1-工具选择错误" tabindex="-1">6.1 工具选择错误 <a class="header-anchor" href="#_6-1-工具选择错误" aria-label="Permalink to &quot;6.1 工具选择错误&quot;">​</a></h2><p>表现：模型选错工具或参数乱填。<br> 优化：</p><ul><li>工具描述写清“何时用”</li><li>减少同时暴露的工具数量（按场景路由）</li><li>在调用前做参数校验</li></ul><h2 id="_6-2-调用链过长" tabindex="-1">6.2 调用链过长 <a class="header-anchor" href="#_6-2-调用链过长" aria-label="Permalink to &quot;6.2 调用链过长&quot;">​</a></h2><p>表现：一个问题触发很多无效调用，延迟高。<br> 优化：</p><ul><li>设置最大调用步数</li><li>增加 early stop 条件</li><li>对常见问题做缓存</li></ul><h2 id="_6-3-高风险操作" tabindex="-1">6.3 高风险操作 <a class="header-anchor" href="#_6-3-高风险操作" aria-label="Permalink to &quot;6.3 高风险操作&quot;">​</a></h2><p>表现：模型直接执行不可逆操作（删除、发送、改库）。<br> 优化：</p><ul><li>权限分级</li><li>人工确认（human-in-the-loop）</li><li>干跑模式（dry-run）与审计日志</li></ul><h2 id="_6-4-工具返回噪声大" tabindex="-1">6.4 工具返回噪声大 <a class="header-anchor" href="#_6-4-工具返回噪声大" aria-label="Permalink to &quot;6.4 工具返回噪声大&quot;">​</a></h2><p>表现：工具返回太多无关数据，模型理解困难。<br> 优化：</p><ul><li>返回精简字段</li><li>提供摘要层（result summary）</li><li>对大结果做分页与筛选</li></ul><hr><h2 id="七、tool-use-与-mcp、skills、agent-的关系" tabindex="-1">七、Tool Use 与 MCP、Skills、Agent 的关系 <a class="header-anchor" href="#七、tool-use-与-mcp、skills、agent-的关系" aria-label="Permalink to &quot;七、Tool Use 与 MCP、Skills、Agent 的关系&quot;">​</a></h2><ul><li><strong>MCP</strong>：定义工具/资源如何标准化暴露（能力接口层）</li><li><strong>Skills</strong>：定义在什么场景下如何使用工具（策略层）</li><li><strong>Agent</strong>：在多步任务中决策何时调什么工具（执行编排层）</li></ul><p>三者关系可以理解为：</p><ul><li>MCP 提供“有什么工具可用”</li><li>Skills 提供“工具应该怎么用”</li><li>Agent 决定“当前这一步要不要用、用哪个”</li></ul><hr><h2 id="八、评估-tool-use-效果" tabindex="-1">八、评估 Tool Use 效果 <a class="header-anchor" href="#八、评估-tool-use-效果" aria-label="Permalink to &quot;八、评估 Tool Use 效果&quot;">​</a></h2><p>仅看“回答是否通顺”不够，建议看这些指标：</p><ol><li><strong>工具调用成功率</strong>（调用是否正常返回）</li><li><strong>工具选择准确率</strong>（是否选对工具）</li><li><strong>任务完成率</strong>（最终任务是否完成）</li><li><strong>平均调用步数</strong>（是否高效）</li><li><strong>端到端时延与成本</strong></li><li><strong>高风险操作误触发率</strong></li></ol><p>这些指标能直接反映 Tool Use 是否“可上线”。</p><hr><h2 id="九、实践建议-落地顺序" tabindex="-1">九、实践建议（落地顺序） <a class="header-anchor" href="#九、实践建议-落地顺序" aria-label="Permalink to &quot;九、实践建议（落地顺序）&quot;">​</a></h2><ol><li>先做 2-3 个高价值工具（不要一次接太多）</li><li>定义清晰 schema 与错误码</li><li>建立调用日志和可观测性</li><li>增加参数校验与权限控制</li><li>再逐步引入多工具编排与自动化策略</li></ol><p>这样可以从“可用”稳步走向“可控、可审计、可扩展”。</p><hr><h2 id="十、小结" tabindex="-1">十、小结 <a class="header-anchor" href="#十、小结" aria-label="Permalink to &quot;十、小结&quot;">​</a></h2><ol><li>Tool Use 是 LLM 从“会说”到“会做”的关键能力。</li><li>核心闭环是：判断是否调用 -&gt; 选择工具 -&gt; 执行 -&gt; 用结果继续推理。</li><li>工具接口设计（职责、参数、返回、错误）决定了系统上限。</li><li>生产落地必须重视权限、审计、错误恢复与性能指标。</li><li>与 MCP、Skills、Agent 协同后，Tool Use 才能形成稳定的自动化能力。</li></ol><p>当模型拥有可靠的工具使用能力，它不再只是回答问题，而是可以真正“完成任务”。</p>',67)]))}const g=o(t,[["render",r]]);export{p as __pageData,g as default};
